(function(){
  function qs(s,c){return (c||document).querySelector(s)}
  function qsa(s,c){return Array.prototype.slice.call((c||document).querySelectorAll(s))}
  function escHtml(str){return String(str||'').replace(/[&<>'"]/g,function(m){return({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[m]})}

  document.addEventListener('DOMContentLoaded',function(){
    var toggle=qs('.menu-toggle'),nav=qs('nav');
    if(toggle&&nav){toggle.addEventListener('click',function(){var open=nav.classList.toggle('open');toggle.setAttribute('aria-expanded',open?'true':'false')})}

    var params=new URLSearchParams(window.location.search);
    var sentBanner=qs('[data-sent-banner]');
    if(sentBanner&&params.get('sent')==='1') sentBanner.hidden=false;

    var modelName=(params.get('title')||params.get('model')||'').trim();
    var modelLink=(params.get('modelLink')||params.get('link')||'').trim();
    var modelLinkInput=qs('#modelLink'),prefillBanner=qs('[data-prefill-banner]');
    var validLink=false;
    try{var parsed=new URL(modelLink);validLink=parsed.protocol==='http:'||parsed.protocol==='https:';}catch(err){}
    if(validLink&&modelLinkInput&&!modelLinkInput.value) modelLinkInput.value=modelLink;
    if(prefillBanner) prefillBanner.hidden=!(modelName||validLink);

    var quoteForm=qs('.quote-form');
    if(quoteForm){
      var estimateOutput=qs('[data-estimator-output]',quoteForm),quantityField=qs('#quantity',quoteForm),materialField=qs('#material',quoteForm),serviceField=qs('#serviceType',quoteForm),urgencyField=qs('#urgency',quoteForm),cityField=qs('#deliveryCity',quoteForm),deliveryOutput=qs('[data-delivery-output]',quoteForm);
      function updateEstimate(){
        if(!estimateOutput) return;
        var qty=Math.max(parseInt((quantityField&&quantityField.value)||'1',10),1);
        var material=((materialField&&materialField.value)||'PLA').toUpperCase();
        var materialFactor={PLA:1,PETG:1.2,ABS:1.3,TPU:1.4,'BILMIYORUM':1.15}[material]||1;
        var service=((serviceField&&serviceField.value)||'3D Baskı');
        var serviceFactor=service.indexOf('Tasarım')>-1?1.45:service.indexOf('Kurumsal')>-1?1.6:1;
        var rushFactor=urgencyField&&urgencyField.value==='rush'?1.3:1;
        var low=Math.max(350,Math.round(220*qty*materialFactor*serviceFactor*rushFactor));
        var high=Math.round(low*1.35);
        estimateOutput.textContent='₺'+low.toLocaleString('tr-TR')+' - ₺'+high.toLocaleString('tr-TR');
      }
      function updateDelivery(){
        if(!deliveryOutput||!cityField) return;
        var city=cityField.value;
        var day=urgencyField&&urgencyField.value==='rush'?2:5;
        var transit={istanbul:1,ankara:2,izmir:2,other:3}[city]||0;
        if(!city){deliveryOutput.textContent='Şehir seçtiğinizde tahmini aralık gösterilir.';return;}
        deliveryOutput.textContent='Tahmini teslim: '+(day+transit)+' - '+(day+transit+2)+' iş günü';
      }
      [quantityField,materialField,serviceField,urgencyField].forEach(function(f){if(f){f.addEventListener('input',updateEstimate);f.addEventListener('change',updateEstimate)}});
      [urgencyField,cityField].forEach(function(f){if(f){f.addEventListener('change',updateDelivery)}});
      updateEstimate();updateDelivery();

      var autoKey=quoteForm.getAttribute('data-autosave');
      if(autoKey){
        var fields=qsa('input,select,textarea',quoteForm).filter(function(el){return el.name&&!/file|submit|hidden|checkbox|radio/.test(el.type)});
        try{var saved=localStorage.getItem(autoKey);if(saved){var data=JSON.parse(saved);fields.forEach(function(el){if(data[el.name]) el.value=data[el.name]})}}catch(err){}
        fields.forEach(function(el){el.addEventListener('input',function(){try{var payload={};fields.forEach(function(field){payload[field.name]=field.value});localStorage.setItem(autoKey,JSON.stringify(payload))}catch(err){}})});
        quoteForm.addEventListener('submit',function(){try{localStorage.removeItem(autoKey)}catch(err){}})
      }
    }

    var products=window.MINIFAB_PRODUCTS||null,productsGrid=qs('#products-grid');
    if(products&&productsGrid&&!productsGrid.children.length){
      productsGrid.innerHTML=products.map(function(p){
        var teklif='teklif.html?model='+encodeURIComponent(p.title)+'&link='+encodeURIComponent(p.link);
        return '<article class="card product-card generated-card" data-category="'+escHtml(p.category)+'" data-title="'+escHtml(p.title)+'"><a class="card-main-link" href="'+escHtml(p.link)+'" target="_blank" rel="noopener noreferrer"><img class="topic-thumb" src="'+escHtml(p.img)+'" width="700" height="420" loading="lazy" decoding="async" alt="'+escHtml(p.title)+' 3D baskı örneği" /><h2>'+escHtml(p.title)+'</h2></a><p>'+escHtml(p.description)+'</p><div class="meta-row"><span class="tag">'+escHtml(p.material)+'</span><span class="tag">'+escHtml(p.time)+'</span><span class="tag">'+escHtml(p.category)+'</span></div><div class="quote-actions"><a class="btn btn-secondary" href="'+escHtml(p.link)+'" target="_blank" rel="noopener noreferrer">Kaynak Modeli Aç</a><a class="btn btn-primary" href="'+teklif+'">Bu iş için teklif al</a></div></article>';
      }).join('');
    }

    function applyCardFilters(){
      var activeBtn=qs('.filter-btn.active'),key=activeBtn?activeBtn.getAttribute('data-filter'):'all';
      qsa('[data-live-search]').forEach(function(input){
        var target=input.getAttribute('data-live-search'),term=(input.value||'').trim().toLowerCase(),visible=0;
        qsa(target).forEach(function(card){
          var cat=card.getAttribute('data-category');
          var show=(key==='all'||cat===key)&&((card.textContent||'').toLowerCase().indexOf(term)>-1||!term);
          card.style.display=show?'block':'none';
          if(show) visible++;
        });
        var counter=qs('[data-results-count="'+target+'"]');
        if(counter) counter.textContent=visible+' sonuç listeleniyor.';
      });
    }

    qsa('.filter-btn').forEach(function(btn){btn.addEventListener('click',function(){qsa('.filter-btn').forEach(function(x){x.classList.remove('active')});btn.classList.add('active');applyCardFilters()})});
    qsa('[data-live-search]').forEach(function(input){input.addEventListener('input',applyCardFilters)});
    applyCardFilters();
  });
})();
